function reverseString(str) {
  return str.split('').reverse().join('');
}

console.log(reverseString('hello'));  // console.logで 'olleh' を表示

function findMax(arr) {
  return Math.max(...arr);
}

console.log(findMax([1, 2, 3, 4, 5]));  // console.logで '5' を表示

function stringLength(str) {
  return str.length;
}

console.log(stringLength('hello'));  // console.logで '5' を表示

function concatStrings(str1, str2) {
  return str1 + str2;
}

console.log(concatStrings('Hello', ' World!'));  // console.logで 'Hello World!' を表示

function evaluateNumber(n) {
  if (n > 0) {
    return 'Positive';
  } else if (n === 0) {
    return 'Zero';
  } else {
    return 'Negative';
  }
}

console.log(evaluateNumber(0));  // console.logで 'Zero' を表示

function splitString(str, delimiter) {
  return str.split(delimiter);
}

console.log(splitString('apple,banana,orange', ','));  // console.logで ['apple', 'banana', 'orange'] を表示

function countElements(arr) {
  return arr.length;
}

console.log(countElements(['apple', 'banana', 'orange']));  // console.logで '3' を表示

function negateBool(b) {
  return !b;
}

console.log(negateBool(true));  // console.logで 'false' を表示

function sumArray(arr) {
  return arr.reduce((acc, curr) => acc + curr, 0);
}

console.log(sumArray([1, 2, 3, 4, 5]));  // console.logで '15' を表示

function repeatString(str, n) {
  return str.repeat(n);
}

console.log(repeatString('abc', 3));  // console.logで 'abcabcabc' を表示

function filterArray(arr, num) {
  return arr.filter(x => x > num);
}

console.log(filterArray([1, 2, 3, 4, 5], 3));  // console.logで '[4, 5]' を表示

function reverseString(str) {
  return str.split('').reverse().join('');
}

console.log(reverseString('javascript'));  // console.logで 'tpircsavaj' を表示

function maxOfArray(arr) {
  return Math.max(...arr);
}

console.log(maxOfArray([1, 2, 3, 4, 5]));  // console.logで '5' を表示

function removeDuplicates(arr) {
  return [...new Set(arr)];
}

console.log(removeDuplicates([1, 2, 2, 3, 3, 3]));  // console.logで '[1, 2, 3]' を表示

function countOccurrences(arr, val) {
  return arr.filter(x => x === val).length;
}

console.log(countOccurrences([1, 2, 2, 3, 3, 3], 2));  // console.logで '2' を表示

function range(start, end) {
  return Array.from({length: end - start + 1}, (_, i) => start + i);
}

console.log(range(2, 5));  // console.logで '[2, 3, 4, 5]' を表示

function shuffle(arr) {
  let array = arr.slice();
  for (let i = array.length - 1; i > 0; i--) {
    let j = Math.floor(Math.random() * (i + 1));
    [array[i], array[j]] = [array[j], array[i]];
  }
  return array;
}

console.log(shuffle([1, 2, 3, 4, 5]));  // console.logで '[3, 1, 2, 5, 4]' のようなランダムな配列を表示

function mostFrequentCharacter(str) {
  const frequency = str.split('').reduce((a, v) => (a[v] = (a[v] || 0) + 1, a), {});
  return Object.keys(frequency).reduce((a, v) => frequency[v] > frequency[a] ? v : a);
}

console.log(mostFrequentCharacter('javascript'));  // console.logで 'a' を表示

function parityBit(binStr) {
  const count = binStr.split('').reduce((a, b) => a + Number(b), 0);
  return count % 2 === 0 ? '0' : '1';
}

console.log(parityBit('1011'));  // console.logで '1' を表示

function digitalRoot(num) {
  if (num < 10) return num;
  return digitalRoot(num.toString().split('').reduce((a, b) => a + Number(b), 0));
}

console.log(digitalRoot(123456));  // console.logで '3' を表示
